import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    best_node = None
    best_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        dist_to_node = np.linalg.norm(cur_truck_pos - customer)
        time_to_node = dist_to_node / truck_speed
        urgency = time_windows[i][1] - current_time - time_to_node

        if urgency <= 0:
            score = dist_to_node
        else:
            score = dist_to_node + urgency

        if score < best_score:
            best_score = score
            best_node = i

    return best_node
